const PICKUP_HEART = [
  5, 2, 11, 2, 13, 5, 14, 7, 14, 11, 11, 15, 9, 15, 6, 13, 4, 11, 3, 8, 3, 5,
];
const PICKUP_KEY = [11, 3, 12, 4, 12, 7, 9, 13, 5, 13, 4, 7, 4, 4, 5, 3];
const PICKUP_COIN = [0, 2, 2, 0, 6, 0, 8, 2, 8, 6, 6, 8, 2, 8, 0, 6];

export function pickup(kind: PickupKind): number[] {
  switch (kind) {
    case PickupKind.HEART:
      return PICKUP_HEART;
    case PickupKind.KEY:
      return PICKUP_KEY;
    case PickupKind.COIN_1:
    case PickupKind.COIN_5:
    case PickupKind.COIN_10:
      return PICKUP_COIN;
  }
}

export function pickupPivotX(kind: PickupKind): number {
  switch (kind) {
    case PickupKind.HEART:
      return 8;
    case PickupKind.KEY:
      return 8;
    case PickupKind.COIN_1:
    case PickupKind.COIN_5:
    case PickupKind.COIN_10:
      return 4;
  }
}

const PICKUP_HEART_PHYS = [
  7, 4, 10, 4, 12, 5, 13, 6, 13, 11, 12, 13, 11, 14, 9, 14, 7, 13, 5, 11, 4, 8, 5, 6,
];
const PICKUP_KEY_PHYS = [
  11, 3, 12, 4, 12, 7, 11, 8, 9, 8, 9, 13, 5, 13, 5, 10, 7, 10, 7, 8, 5, 8, 4, 7, 4, 4, 5, 3,
];
const PICKUP_COIN_PHYS = [2, 2, 3, 1, 5, 1, 6, 2, 6, 6, 5, 7, 3, 7, 2, 6];

export const PICKUP_HEART_PHYS_PIVOT_X = 0;
export const PICKUP_KEY_PHYS_PIVOT_X = 0;
export const PICKUP_COIN_PHYS_PIVOT_X = 0;

export function pickupPhysics(kind: PickupKind): number[] {
  switch (kind) {
    case PickupKind.HEART:
      return PICKUP_HEART_PHYS;
    case PickupKind.KEY:
      return PICKUP_KEY_PHYS;
    case PickupKind.COIN_1:
    case PickupKind.COIN_5:
    case PickupKind.COIN_10:
      return PICKUP_COIN_PHYS;
  }
}

export function pickupPhysicsPivotX(kind: PickupKind): number {
  switch (kind) {
    case PickupKind.HEART:
      return PICKUP_HEART_PHYS_PIVOT_X;
    case PickupKind.KEY:
      return PICKUP_KEY_PHYS_PIVOT_X;
    case PickupKind.COIN_1:
    case PickupKind.COIN_5:
    case PickupKind.COIN_10:
      return PICKUP_COIN_PHYS_PIVOT_X;
  }
}

